const express = require('express');
const multer = require('multer');
const fs = require('fs');
const path = require('path');
const xml2js = require('xml2js');

const app = express();
const upload = multer({ dest: 'uploads/' });

app.post('/upload-xml', upload.single('file'), (req, res) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  const filePath = path.join(__dirname, req.file.path);
  fs.readFile(filePath, 'utf8', (err, xmlData) => {
    if (err) {
      fs.unlinkSync(filePath);
      return res.status(500).json({ error: 'Failed to read uploaded file' });
    }

    const parser = new xml2js.Parser({ explicitArray: false, mergeAttrs: true });
    parser.parseString(xmlData, (err, result) => {
      fs.unlinkSync(filePath);
      if (err) {
        return res.status(400).json({ error: 'Invalid XML format' });
      }

      // Extract configuration settings from parsed XML
      const config = extractConfiguration(result);
      res.json({ config });
    });
  });
});

function extractConfiguration(parsedXml) {
  // Example: assuming XML has a root <configuration> element
  if (parsedXml && parsedXml.configuration) {
    return parsedXml.configuration;
  }
  return {};
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});